mapper.select:
SELECT p.product_no, p.product_no AS id, p.company_no, p.product_name, p.product_name AS name, p.product_details, p.product_details AS content, p.original_price, p.original_price AS price, p.is_active, p.img_url, p.img_url AS thumbnail, p.large_category, p.medium_category, p.deposit, p.reg_date, c.com_name, /* 💡 고도화 핵심: 어제 우리가 구축한 검색 필터 하드웨어를 100% 보존하기 위해, SELECT 절 내부에서 해당 상품의 모든 태그 텍스트들을 콤마로 예쁘게 묶어 공급하는 독립 서브쿼리 레일 이식 */ ( SELECT GROUP_CONCAT(pt_all.tag SEPARATOR ',') FROM product_tag_map ptm_all INNER JOIN product_tag pt_all ON ptm_all.tag_id = pt_all.id WHERE ptm_all.product_no = p.product_no ) AS tag FROM product p LEFT JOIN company c ON p.company_no = c.company_no
INNER JOIN product_tag_map ptm ON p.product_no = ptm.product_no INNER JOIN product_tag pt ON ptm.tag_id = pt.id
AND p.large_category = #{largeCategory}
AND p.medium_category = #{mediumCategory}
AND pt.tag IN
#{tag}
GROUP BY p.product_no
HAVING COUNT(DISTINCT pt.tag) = #{tagSize}
ORDER BY p.reg_date DESC
